+
+      // fcmp oeq/une (select (fcmp ord X, 0.0), X, 0.0), C
+      //   --> fcmp oeq/une X, C
+      // The select converts NaN to 0.0. For non-zero C, the comparison with 0.0
+      // gives the same result as comparison with NaN (both false for oeq, both true for une).
+      if (FCmpInst::isEquality(Pred) && !match(RHSC, m_AnyZeroFP())) {
+        Value *SelX;
+        if (match(LHSI, m_Select(
