+                m_Deferred(SelX), m_AnyZeroFP())) ||
+            match(LHSI, m_Select(
+                m_SpecificFCmp(FCmpInst::FCMP_UNO, m_Value(SelX), m_AnyZeroFP()),
+                m_AnyZeroFP(), m_Deferred(SelX))))
+          return replaceOperand(I, 0, SelX);
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;

